const solve = (chunks, queries) => {
    // Step 1: Concatenate chunks to form S
    const S = chunks.join('');
    const N = S.length;

    // Map to store counts of valid words found in S
    const wordCounts = new Map();

    // Helper functions for character checks
    const isLetter = (char) => char >= 'a' && char <= 'z';
    const isHyphen = (char) => char === '-';

    // Step 2: Parse S to find all valid words
    let i = 0;
    while (i < N) {
        const char = S[i];

        if (isLetter(char)) {
            // Start of a potential word
            const start = i;
            let j = i + 1;

            // Extend the word as long as possible based on rules
            while (j < N) {
                const C = S[j];

                if (isLetter(C)) {
                    j++;
                } else if (isHyphen(C)) {
                    // Check hyphen validity: must be surrounded by letters
                    // S[j-1] is guaranteed to be part of the current word and thus a letter (since it was processed previously)
                    // We must check S[j+1]
                    const isRightLetter = j + 1 < N && isLetter(S[j+1]);

                    if (isRightLetter) {
                        j++; // Valid hyphen, extend word
                    } else {
                        // Invalid hyphen placement, acts as a delimiter. Word ends before this hyphen.
                        break;
                    }
                } else {
                    // Standard delimiter (space, punctuation, etc.). Word ends before this character.
                    break;
                }
            }

            // The maximal valid word is S[start...j-1]
            const word = S.substring(start, j);

            // Count the word
            wordCounts.set(word, (wordCounts.get(word) || 0) + 1);

            // Advance i past the word we just processed.
            i = j;
        } else {
            // Character is a delimiter (space, punctuation, or an invalid hyphen that wasn't part of a word segment)
            i++;
        }
    }

    // Step 3: Generate the result array based on queries
    const ans = [];
    for (const query of queries) {
        ans.push(wordCounts.get(query) || 0);
    }

    return ans;
};

